import{_ as t,o as n,c as s,a4 as l}from"./chunks/framework._in6GHBg.js";const u=JSON.parse('{"title":"生物学习方法","description":"","frontmatter":{},"headers":[],"relativePath":"biology/method.md","filePath":"biology/method.md"}'),i={name:"biology/method.md"};function e(o,a,r,p,d,g){return n(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="生物学习方法" tabindex="-1">生物学习方法 <a class="header-anchor" href="#生物学习方法" aria-label="Permalink to &quot;生物学习方法&quot;">​</a></h1><p><strong>从&quot;死记硬背&quot;到&quot;理解记忆&quot;——生物学习的正确打开方式</strong></p><hr><h2 id="一、本章地图" tabindex="-1">一、本章地图 <a class="header-anchor" href="#一、本章地图" aria-label="Permalink to &quot;一、本章地图&quot;">​</a></h2><h3 id="核心目标" tabindex="-1">核心目标 <a class="header-anchor" href="#核心目标" aria-label="Permalink to &quot;核心目标&quot;">​</a></h3><p>读完本文档，你将：</p><ol><li>理解生物学习的本质是&quot;理解生命机制&quot;</li><li>掌握生物学习的三大核心方法</li><li>建立适合自己的学习习惯</li></ol><h3 id="知识网络" tabindex="-1">知识网络 <a class="header-anchor" href="#知识网络" aria-label="Permalink to &quot;知识网络&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>生物学习方法</span></span>
<span class="line"><span>├── 思维转变</span></span>
<span class="line"><span>│   ├── 从背诵到理解</span></span>
<span class="line"><span>│   ├── 从孤立到联系</span></span>
<span class="line"><span>│   └── 从静态到动态</span></span>
<span class="line"><span>├── 核心方法</span></span>
<span class="line"><span>│   ├── 图解法（画流程图、示意图）</span></span>
<span class="line"><span>│   ├── 比较法（表格对比）</span></span>
<span class="line"><span>│   ├── 归纳法（构建知识网络）</span></span>
<span class="line"><span>│   └── 应用法（用原理解释现象）</span></span>
<span class="line"><span>├── 记忆技巧</span></span>
<span class="line"><span>│   ├── 理解优先</span></span>
<span class="line"><span>│   ├── 联想记忆</span></span>
<span class="line"><span>│   ├── 口诀记忆</span></span>
<span class="line"><span>│   └── 重复巩固</span></span>
<span class="line"><span>└── 应试技巧</span></span>
<span class="line"><span>    ├── 选择题策略</span></span>
<span class="line"><span>    ├── 填空题策略</span></span>
<span class="line"><span>    └── 长句表达策略</span></span></code></pre></div><hr><h2 id="二、思维转变-从-背诵-到-理解" tabindex="-1">二、思维转变：从&quot;背诵&quot;到&quot;理解&quot; <a class="header-anchor" href="#二、思维转变-从-背诵-到-理解" aria-label="Permalink to &quot;二、思维转变：从&quot;背诵&quot;到&quot;理解&quot;&quot;">​</a></h2><h3 id="错误观念-生物就是背" tabindex="-1">错误观念：生物就是背 <a class="header-anchor" href="#错误观念-生物就是背" aria-label="Permalink to &quot;错误观念：生物就是背&quot;">​</a></h3><p><strong>错误做法</strong>：</p><ul><li>❌ 把课本逐字逐句背下来</li><li>❌ 死记概念定义</li><li>❌ 孤立记忆知识点</li></ul><p><strong>结果</strong>：</p><ul><li>背了就忘</li><li>换个问法就不会</li><li>综合题完全没思路</li></ul><hr><h3 id="正确观念-生物是理解生命的逻辑" tabindex="-1">正确观念：生物是理解生命的逻辑 <a class="header-anchor" href="#正确观念-生物是理解生命的逻辑" aria-label="Permalink to &quot;正确观念：生物是理解生命的逻辑&quot;">​</a></h3><p><strong>正确做法</strong>：</p><ul><li>✅ 理解分子机制（为什么这样？）</li><li>✅ 建立知识联系（这个和那个有什么关系？）</li><li>✅ 用原理解释现象（这个现象说明了什么？）</li></ul><p><strong>结果</strong>：</p><ul><li>记忆更牢固</li><li>能应对变形题</li><li>综合题有思路</li></ul><h3 id="三个关键转变" tabindex="-1">三个关键转变 <a class="header-anchor" href="#三个关键转变" aria-label="Permalink to &quot;三个关键转变&quot;">​</a></h3><p><strong>转变1：从孤立到联系</strong></p><ul><li>不是记&quot;线粒体是能量工厂&quot;</li><li>而是理解&quot;为什么线粒体是能量工厂？（因为它进行有氧呼吸的第二、三阶段，产生大量ATP）&quot;</li><li>联系：线粒体→有氧呼吸→ATP→生命活动需要能量</li></ul><p><strong>转变2：从静态到动态</strong></p><ul><li>不是记&quot;光合作用产生有机物&quot;</li><li>而是理解&quot;光合作用是如何一步步进行的？&quot;</li><li>动态：光反应（水的光解→ATP、[H]）→暗反应（CO₂固定→C₃还原→有机物）</li></ul><p><strong>转变3：从微观到宏观</strong></p><ul><li>不是只记分子层面的过程</li><li>而是理解&quot;分子变化如何影响细胞功能，进而影响个体表现&quot;</li><li>层次：DNA→蛋白质→细胞结构→细胞功能→个体性状</li></ul><hr><h2 id="三、核心学习方法" tabindex="-1">三、核心学习方法 <a class="header-anchor" href="#三、核心学习方法" aria-label="Permalink to &quot;三、核心学习方法&quot;">​</a></h2><h3 id="方法1-图解法-⭐" tabindex="-1">方法1：图解法 ⭐ <a class="header-anchor" href="#方法1-图解法-⭐" aria-label="Permalink to &quot;方法1：图解法 ⭐&quot;">​</a></h3><p><strong>适用</strong>：</p><ul><li>代谢过程（光合作用、呼吸作用）</li><li>调节过程（神经调节、激素调节）</li><li>遗传过程（DNA复制、转录翻译）</li></ul><p><strong>步骤</strong>：</p><ol><li><strong>读课本</strong>：理解文字描述的过程</li><li><strong>画草图</strong>：边读边画，用箭头表示流程</li><li><strong>标关键</strong>：标出关键物质、关键变化、关键场所</li><li><strong>简化和美化</strong>：整理成清晰的流程图</li><li><strong>复述</strong>：看着图，用自己的话讲一遍</li></ol><p><strong>示例</strong>：光合作用过程图</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>光反应（类囊体薄膜）</span></span>
<span class="line"><span>  光 → 水光解 → O₂ + [H]</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>      ADP + Pi → ATP</span></span>
<span class="line"><span></span></span>
<span class="line"><span>暗反应（叶绿体基质）</span></span>
<span class="line"><span>  CO₂ + C₅ → 2C₃</span></span>
<span class="line"><span>  2C₃ + [H] + ATP → (CH₂O) + C₅</span></span></code></pre></div><hr><h3 id="方法2-比较法-⭐" tabindex="-1">方法2：比较法 ⭐ <a class="header-anchor" href="#方法2-比较法-⭐" aria-label="Permalink to &quot;方法2：比较法 ⭐&quot;">​</a></h3><p><strong>适用</strong>：</p><ul><li>易混淆的概念（有丝分裂vs减数分裂）</li><li>相似的结构（原核vs真核细胞）</li><li>相似的生理过程（体液免疫vs细胞免疫）</li></ul><p><strong>步骤</strong>：</p><ol><li><strong>找出比较对象</strong></li><li><strong>确定比较维度</strong>（过程、场所、结果、意义等）</li><li><strong>制作对比表格</strong></li><li><strong>找出核心区别</strong></li></ol><p><strong>示例</strong>：有丝分裂vs减数分裂</p><table tabindex="0"><thead><tr><th style="text-align:center;">比较项目</th><th style="text-align:center;">有丝分裂</th><th style="text-align:center;">减数分裂</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>发生部位</strong></td><td style="text-align:center;">体细胞</td><td style="text-align:center;">生殖腺</td></tr><tr><td style="text-align:center;"><strong>分裂次数</strong></td><td style="text-align:center;">1次</td><td style="text-align:center;">2次</td></tr><tr><td style="text-align:center;"><strong>同源染色体配对</strong></td><td style="text-align:center;">无</td><td style="text-align:center;">有（减Ⅰ前期）</td></tr><tr><td style="text-align:center;"><strong>染色体数目变化</strong></td><td style="text-align:center;">不变</td><td style="text-align:center;">减半</td></tr><tr><td style="text-align:center;"><strong>DNA复制次数</strong></td><td style="text-align:center;">1次</td><td style="text-align:center;">1次</td></tr><tr><td style="text-align:center;"><strong>子细胞染色体数</strong></td><td style="text-align:center;">2n</td><td style="text-align:center;">n</td></tr><tr><td style="text-align:center;"><strong>子细胞类型</strong></td><td style="text-align:center;">2个体细胞</td><td style="text-align:center;">4个生殖细胞</td></tr><tr><td style="text-align:center;"><strong>意义</strong></td><td style="text-align:center;">生长、修复</td><td style="text-align:center;">产生配子、变异</td></tr></tbody></table><hr><h3 id="方法3-归纳法" tabindex="-1">方法3：归纳法 <a class="header-anchor" href="#方法3-归纳法" aria-label="Permalink to &quot;方法3：归纳法&quot;">​</a></h3><p><strong>适用</strong>：</p><ul><li>构建知识网络</li><li>总结规律</li><li>整理实验方法</li></ul><p><strong>步骤</strong>：</p><ol><li><strong>梳理知识点</strong>：把零散知识点列出来</li><li><strong>找联系</strong>：找出知识点之间的关系</li><li><strong>画网络图</strong>：用箭头、连线表示关系</li><li><strong>补充完善</strong>：不断添加新学到的内容</li></ol><p><strong>示例</strong>：蛋白质相关知识网络</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>元素组成（C、H、O、N等）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>基本单位：氨基酸（结构通式）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>连接方式：脱水缩合 → 肽键</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>结构层次：氨基酸 → 多肽链 → 蛋白质</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>结构多样性：氨基酸种类、数目、排列顺序、空间结构</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>功能多样性：结构蛋白、酶、抗体、激素、载体等</span></span></code></pre></div><hr><h3 id="方法4-应用法" tabindex="-1">方法4：应用法 <a class="header-anchor" href="#方法4-应用法" aria-label="Permalink to &quot;方法4：应用法&quot;">​</a></h3><p><strong>适用</strong>：</p><ul><li>检验理解程度</li><li>应对新情境题</li></ul><p><strong>步骤</strong>：</p><ol><li><strong>学了一个原理后，主动想</strong>：这个原理能解释什么现象？</li><li><strong>看到现象时，主动想</strong>：这个现象用什么原理解释？</li><li><strong>做题时，先判断</strong>：这道题考什么知识点？</li></ol><p><strong>示例</strong>：</p><ul><li>学了&quot;酶的专一性&quot;→ 能解释&quot;为什么消化酶不能消化自己的细胞&quot;</li><li>看到&quot;发烧时食欲下降&quot;→ 用&quot;酶的活性受温度影响&quot;解释</li></ul><hr><h2 id="四、记忆技巧" tabindex="-1">四、记忆技巧 <a class="header-anchor" href="#四、记忆技巧" aria-label="Permalink to &quot;四、记忆技巧&quot;">​</a></h2><h3 id="技巧1-理解优先" tabindex="-1">技巧1：理解优先 <a class="header-anchor" href="#技巧1-理解优先" aria-label="Permalink to &quot;技巧1：理解优先&quot;">​</a></h3><p><strong>原理</strong>：理解了的东西更容易记住。</p><p><strong>做法</strong>：</p><ul><li>先理解&quot;为什么&quot;，再记&quot;是什么&quot;</li><li>用自己的话解释一遍</li><li>能讲给别人听，才算真理解</li></ul><hr><h3 id="技巧2-联想记忆" tabindex="-1">技巧2：联想记忆 <a class="header-anchor" href="#技巧2-联想记忆" aria-label="Permalink to &quot;技巧2：联想记忆&quot;">​</a></h3><p><strong>原理</strong>：把新知识与已有知识联系起来。</p><p><strong>示例</strong>：</p><ul><li>记忆&quot;线粒体&quot;→ 联想：&quot;线&quot;像DNA的双螺旋，&quot;粒&quot;是颗粒状，它是能量&quot;体&quot;育场</li><li>记忆&quot;8种必需氨基酸&quot;→ 谐音：&quot;甲硫缬异亮苯，色苏赖 bright&quot;</li></ul><hr><h3 id="技巧3-口诀记忆" tabindex="-1">技巧3：口诀记忆 <a class="header-anchor" href="#技巧3-口诀记忆" aria-label="Permalink to &quot;技巧3：口诀记忆&quot;">​</a></h3><p><strong>适用</strong>：</p><ul><li>步骤性知识</li><li>并列性知识</li></ul><p><strong>示例</strong>：</p><ul><li>有丝分裂各期特点：&quot;前期膜仁消失现两体，中期形定数晰赤道齐，后期点裂数加均两极，末期两消两现重开始&quot;</li><li>显微镜使用步骤：&quot;取镜安放对光调焦观察收镜&quot;</li></ul><hr><h3 id="技巧4-重复巩固" tabindex="-1">技巧4：重复巩固 <a class="header-anchor" href="#技巧4-重复巩固" aria-label="Permalink to &quot;技巧4：重复巩固&quot;">​</a></h3><p><strong>遗忘曲线</strong>：学完后20分钟遗忘42%，1天后遗忘74%。</p><p><strong>做法</strong>：</p><ul><li><strong>当天复习</strong>：学完当天，回顾一遍流程图</li><li><strong>周末复习</strong>：周末整理本周内容</li><li><strong>考前复习</strong>：考前看速查卡和流程图</li></ul><p><strong>间隔重复</strong>：</p><ul><li>第1次：学习后1天</li><li>第2次：学习后3天</li><li>第3次：学习后7天</li><li>第4次：学习后14天</li></ul><hr><h2 id="五、应试技巧" tabindex="-1">五、应试技巧 <a class="header-anchor" href="#五、应试技巧" aria-label="Permalink to &quot;五、应试技巧&quot;">​</a></h2><h3 id="选择题技巧" tabindex="-1">选择题技巧 <a class="header-anchor" href="#选择题技巧" aria-label="Permalink to &quot;选择题技巧&quot;">​</a></h3><p><strong>读题</strong>：</p><ul><li>圈出关键词：&quot;正确的是&quot;/&quot;错误的是&quot;、&quot;都&quot;/&quot;不都&quot;</li><li>注意限定词：&quot;全部&quot;/&quot;主要&quot;/&quot;一定&quot;/&quot;可能&quot;</li></ul><p><strong>排除法</strong>：</p><ul><li>先排除明显错误的选项</li><li>在剩余选项中比较</li></ul><p><strong>注意陷阱</strong>：</p><ul><li>概念混淆（如混淆细胞器功能）</li><li>以偏概全（如&quot;所有酶都是蛋白质&quot;，忽略了RNA酶）</li><li>偷换概念</li></ul><hr><h3 id="填空题技巧" tabindex="-1">填空题技巧 <a class="header-anchor" href="#填空题技巧" aria-label="Permalink to &quot;填空题技巧&quot;">​</a></h3><p><strong>专业术语</strong>：</p><ul><li>必须使用课本标准术语</li><li>不能写错别字（如&quot;线粒体&quot;不能写成&quot;细粒体&quot;）</li></ul><p><strong>完整准确</strong>：</p><ul><li>不能只写关键词，要语句通顺</li><li>注意数量单位</li></ul><hr><h3 id="长句表达技巧-⭐" tabindex="-1">长句表达技巧 ⭐ <a class="header-anchor" href="#长句表达技巧-⭐" aria-label="Permalink to &quot;长句表达技巧 ⭐&quot;">​</a></h3><p><strong>评分标准</strong>：</p><ul><li>关键词到位</li><li>逻辑链条完整</li><li>专业术语准确</li></ul><p><strong>答题模板</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>因为[原因]，所以[结果]，导致[结论]。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>或：</span></span>
<span class="line"><span>当[条件]时，[机制]发生，使[结果]。</span></span></code></pre></div><p><strong>示例</strong>：</p><ul><li>问：为什么光照增强，光合作用增强？</li><li>差答：因为光强了</li><li>好答：光照强度增强，光反应产生的[H]和ATP增多，为暗反应中C₃的还原提供更多原料，从而增强光合作用</li></ul><p><strong>关键词</strong>：光照强度、光反应、[H]、ATP、暗反应、C₃还原</p><hr><h2 id="六、实验题技巧" tabindex="-1">六、实验题技巧 <a class="header-anchor" href="#六、实验题技巧" aria-label="Permalink to &quot;六、实验题技巧&quot;">​</a></h2><h3 id="实验设计题答题框架" tabindex="-1">实验设计题答题框架 <a class="header-anchor" href="#实验设计题答题框架" aria-label="Permalink to &quot;实验设计题答题框架&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 实验目的：验证/探究...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 实验原理：基于...原理</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 实验材料：...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 实验步骤：</span></span>
<span class="line"><span>   (1) 分组编号：将...随机均分为...组，编号为...</span></span>
<span class="line"><span>   (2) 变量处理：</span></span>
<span class="line"><span>       - 对照组：...</span></span>
<span class="line"><span>       - 实验组：...</span></span>
<span class="line"><span>   (3) 控制无关变量：...</span></span>
<span class="line"><span>   (4) 培养/处理相同且适宜的时间</span></span>
<span class="line"><span>   (5) 观察记录：观察...，记录...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 预期结果与结论：</span></span>
<span class="line"><span>   - 若...，则说明...</span></span>
<span class="line"><span>   - 若...，则说明...</span></span></code></pre></div><p><strong>原则</strong>：</p><ul><li><strong>对照原则</strong>：设置对照组</li><li><strong>单一变量原则</strong>：只有一个自变量不同</li><li><strong>平行重复原则</strong>：每组多个样本，多次实验</li></ul><hr><h2 id="七、常见问题faq" tabindex="-1">七、常见问题FAQ <a class="header-anchor" href="#七、常见问题faq" aria-label="Permalink to &quot;七、常见问题FAQ&quot;">​</a></h2><h3 id="faq-1-生物需要背诵吗" tabindex="-1">FAQ 1：生物需要背诵吗？ <a class="header-anchor" href="#faq-1-生物需要背诵吗" aria-label="Permalink to &quot;FAQ 1：生物需要背诵吗？&quot;">​</a></h3><p><strong>答</strong>：需要，但要在理解的基础上背诵。</p><p><strong>建议</strong>：</p><ul><li>先理解原理</li><li>画出流程图</li><li>然后看着流程图复述</li><li>最后闭卷默写</li></ul><hr><h3 id="faq-2-代谢过程总是记不住怎么办" tabindex="-1">FAQ 2：代谢过程总是记不住怎么办？ <a class="header-anchor" href="#faq-2-代谢过程总是记不住怎么办" aria-label="Permalink to &quot;FAQ 2：代谢过程总是记不住怎么办？&quot;">​</a></h3><p><strong>答</strong>：画流程图+分阶段记忆。</p><p><strong>步骤</strong>：</p><ol><li>画出整个过程的流程图</li><li>分成几个阶段（如光反应、暗反应）</li><li>先记每个阶段的总体变化</li><li>再记每个阶段的具体步骤</li><li>每天看一遍流程图</li></ol><hr><h3 id="faq-3-遗传概率计算总出错怎么办" tabindex="-1">FAQ 3：遗传概率计算总出错怎么办？ <a class="header-anchor" href="#faq-3-遗传概率计算总出错怎么办" aria-label="Permalink to &quot;FAQ 3：遗传概率计算总出错怎么办？&quot;">​</a></h3><p><strong>答</strong>：掌握方法+多练习。</p><p><strong>方法</strong>：</p><ol><li>先确定遗传方式（常染色体/性染色体，显性/隐性）</li><li>写出亲本基因型</li><li>画棋盘格或分支图</li><li>注意特殊情况（致死、不完全显性）</li></ol><p><strong>练习</strong>：</p><ul><li>从简单题开始</li><li>逐步增加难度</li><li>总结易错点</li></ul><hr><h3 id="faq-4-时间不够-怎么高效复习" tabindex="-1">FAQ 4：时间不够，怎么高效复习？ <a class="header-anchor" href="#faq-4-时间不够-怎么高效复习" aria-label="Permalink to &quot;FAQ 4：时间不够，怎么高效复习？&quot;">​</a></h3><p><strong>答</strong>：抓重点+用工具。</p><p><strong>抓重点</strong>：</p><ul><li>看进度追踪表，优先红色项目</li><li>重点看流程图和对比表</li><li>做近年真题</li></ul><p><strong>用工具</strong>：</p><ul><li>用速查卡快速过概念</li><li>用套路文件掌握解题方法</li></ul><hr><h2 id="八、本章检查清单" tabindex="-1">八、本章检查清单 <a class="header-anchor" href="#八、本章检查清单" aria-label="Permalink to &quot;八、本章检查清单&quot;">​</a></h2><ul><li>[ ] 理解了生物学习需要&quot;理解优先，记忆其次&quot;</li><li>[ ] 掌握了图解法，会画流程图</li><li>[ ] 掌握了比较法，会制作对比表</li><li>[ ] 掌握了归纳法，能构建知识网络</li><li>[ ] 知道如何回答长句表达题</li><li>[ ] 知道实验设计题的基本框架</li></ul><hr><h2 id="九、配套资源导航" tabindex="-1">九、配套资源导航 <a class="header-anchor" href="#九、配套资源导航" aria-label="Permalink to &quot;九、配套资源导航&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">你的需求</th><th style="text-align:left;">去哪找</th></tr></thead><tbody><tr><td style="text-align:center;">不知道学生物的方法</td><td style="text-align:left;">本文档</td></tr><tr><td style="text-align:center;">想知道各板块掌握情况</td><td style="text-align:left;"><code>Bio-Track-001</code> 进度追踪表</td></tr><tr><td style="text-align:center;">学分子与细胞</td><td style="text-align:left;"><code>Bio-Learn-Detail-001</code> 分子与细胞详解</td></tr><tr><td style="text-align:center;">学遗传</td><td style="text-align:left;"><code>Bio-Learn-Detail-002</code> 遗传与进化详解</td></tr><tr><td style="text-align:center;">考前快速复习</td><td style="text-align:left;"><code>Bio-Review-Tool-002</code> 速查卡</td></tr></tbody></table><hr><p><strong>文档编号</strong>: Bio-Learn-Method-001<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,149)])])}const c=t(i,[["render",e]]);export{u as __pageData,c as default};
